29	// Runner executes agent invocations.
30	type Runner struct {
31		registry *harnessRegistry
32		Config   Config
33		Catalog  *Catalog     // model catalog for routing; defaults to BuiltinCatalog
34		Executor Executor     // injected; defaults to OSExecutor
35		LookPath LookPathFunc // injected; defaults to exec.LookPath
36	
37		// WorkDir is the project root used for loading native agent config.
38		WorkDir string
39	}
