41	// NewRunner creates a runner with defaults.
42	func NewRunner(cfg Config) *Runner {
43		if cfg.Harness == "" {
44			cfg.Harness = DefaultHarness
45		}
46		if cfg.TimeoutMS == 0 {
47			cfg.TimeoutMS = DefaultTimeoutMS
48		}
49		if cfg.WallClockMS == 0 {
50			cfg.WallClockMS = DefaultWallClockMS
51		}
52		if cfg.SessionLogDir == "" {
53			cfg.SessionLogDir = DefaultLogDir
54		}
55		// Build the effective catalog in precedence order (lowest to highest priority):
56		//   1. Built-in seed (DefaultModelCatalogYAML — deterministic fallback for smart/standard/cheap)
57		//   2. Shared ddx-agent catalog (~/.config/agent/models.yaml — authoritative when installed)
58		//   3. User overrides (~/.ddx/model-catalog.yaml — user wins over shared and built-in)
59		catalog := BuiltinCatalog.Clone()
60		if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
61			ApplyCatalogFromService(context.Background(), catalog, svc)
62		}
63		if path := DefaultModelCatalogPath(); path != "" {
64			if yml, err := LoadModelCatalogYAML(path); err == nil && yml != nil {
65				ApplyModelCatalogYAML(catalog, yml)
66			}
67		}
68	
69		r := &Runner{
70			registry: newHarnessRegistry(),
71			Config:   cfg,
72			Catalog:  catalog,
73			Executor: &OSExecutor{},
74			LookPath: DefaultLookPath,
75		}
76		r.registry.LookPath = func(file string) (string, error) {
77			if r.LookPath != nil {
78				return r.LookPath(file)
79			}
80			return DefaultLookPath(file)
81		}
82		return r
83	}
