424	// resolveWallClock picks the absolute wall-clock cap from opts or config.
425	// This bound fires regardless of stream/event activity so a provider that
426	// emits heartbeats cannot pin the worker past the configured duration.
427	func (r *Runner) resolveWallClock(opts RunOptions) time.Duration {
428		if opts.WallClock > 0 {
429			return opts.WallClock
430		}
431		return time.Duration(r.Config.WallClockMS) * time.Millisecond
432	}
