948	// TestProviderConnectivity sends a lightweight probe to check if the provider is reachable and has credits.
949	// Returns ProviderStatus with connectivity information.
950	func (r *Runner) TestProviderConnectivity(harnessName string, timeout time.Duration) ProviderStatus {
951		status := ProviderStatus{Reachable: false}
952	
953		// Skip embedded harnesses - they don't have external providers
954		if harnessName == "virtual" || harnessName == "agent" {
955			status.Reachable = true
956			status.CreditsOK = true
957			return status
958		}
959	
960		harness, ok := r.registry.Get(harnessName)
961		if !ok {
962			status.Error = "unknown harness"
963			return status
964		}
965	
966		// Check if binary exists first
967		if harnessName != "virtual" && harnessName != "agent" {
968			if _, err := r.LookPath(harness.Binary); err != nil {
969				status.Error = "binary not found"
970				return status
971			}
972		}
973	
974		// Send a lightweight probe request to test connectivity
975		probePrompt := "echo ok"
976		opts := RunOptions{
977			Harness: harnessName,
978			Prompt:  probePrompt,
979			Timeout: timeout,
980		}
981	
982		start := time.Now()
983		result, err := r.Run(opts)
984		duration := time.Since(start)
985	
986		if err != nil {
987			status.Error = fmt.Sprintf("probe failed: %v (%.0fs)", err, duration.Seconds())
988			// Check for common error patterns indicating credit/quota issues
989			errStr := strings.ToLower(err.Error())
990			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
991				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
992				status.CreditsOK = false
993			}
994			return status
995		}
996	
997		// Check exit code and error from result
998		if result.ExitCode != 0 || result.Error != "" {
999			errStr := strings.ToLower(result.Error)
1000			status.Error = fmt.Sprintf("probe failed: %s (%.0fs)", result.Error, duration.Seconds())
1001			// Check for credit/quota errors
1002			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
1003				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
1004				status.CreditsOK = false
1005			}
1006			return status
1007		}
1008	
1009		// Probe succeeded
1010		status.Reachable = true
1011		status.CreditsOK = true
1012		return status
1013	}
