211	// through the agent service (RunViaService).
212	func RunCompareViaService(ctx context.Context, workDir string, opts CompareOptions) (*ComparisonRecord, error) {
213		run := func(runOpts RunOptions) (*Result, error) {
214			return RunViaService(ctx, workDir, runOpts)
