228	// defaultResolvePromptForCompare reads inline Prompt or PromptFile.
229	func defaultResolvePromptForCompare(opts RunOptions) (string, error) {
230		prompt := opts.Prompt
231		if opts.PromptFile != "" {
232			data, err := readPromptFileBounded(opts.PromptFile)
233			if err != nil {
234				return "", fmt.Errorf("agent: read prompt file: %w", err)
235			}
236			prompt = string(data)
237		}
238		if prompt == "" {
239			return "", fmt.Errorf("agent: prompt is required")
240		}
241		return prompt, nil
